#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[10001], B[10001];
        scanf("%s", A);
        scanf("%s", B);
        int count = 0;
        int lenA = strlen(A);
        int lenB = strlen(B);
        for (int i = 0; i < lenA; i++) {
            for (int j = 0; j < lenB; j++) {
                if (A[i] == B[j]) {
                    count++;
                    B[j] = '\0';
                    break;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

